+		curwin = w;
+		xrow = w->row;
+		xoff = w->off;
+		xtop = w->top;
+		xleft = w->left;
+		if (w->buf != ex_buf) {
+			ex_buf = w->buf;
+			syn_setft(xb_ft);
+		}
+		syn_scdir(0);
+		for (int i = xtop; i < xtop + w->h; i++)
+			vi_drawrow(i);
+		w = w->next;
+	} while (w != wins);
+	vi_draw_separators();
+	curwin = saved;
+	xrow = srow;
+	xoff = soff;
+	xtop = stop;
+	xleft = sleft;
+	if (savebuf != ex_buf) {
+		ex_buf = savebuf;
+		syn_setft(xb_ft);
+	}
+}
